using BoutiqueInventoryAPI.Data; using BoutiqueInventoryAPI.DTOs; using BoutiqueInventoryAPI.Services; using Microsoft.AspNetCore.Mvc; using Microsoft.EntityFrameworkCore;
namespace BoutiqueInventoryAPI.Controllers;
[ApiController][Route("api/[controller]")] public class WarehousesController:ControllerBase{private readonly BoutiqueDbContext _context; private readonly IStoredProcedureService _spService; public WarehousesController(BoutiqueDbContext context,IStoredProcedureService spService){_context=context;_spService=spService;} [HttpGet] public async Task<IActionResult> GetAll(){return Ok(await _context.Warehouses.Include(w=>w.Products).ToListAsync());} [HttpGet("{id}")] public async Task<IActionResult> GetById(int id){var w=await _context.Warehouses.Include(x=>x.Products).FirstOrDefaultAsync(x=>x.Id==id); return w==null?NotFound("Warehouse not found."):Ok(w);} [HttpPost] public async Task<IActionResult> Create(WarehouseCreateDto dto){var id=await _spService.InsertWarehouseAsync(dto); var w=await _context.Warehouses.FindAsync(id); return CreatedAtAction(nameof(GetById),new{id},w);} [HttpPut("{id}")] public async Task<IActionResult> Update(int id,WarehouseUpdateDto dto){await _spService.UpdateWarehouseAsync(id,dto); var w=await _context.Warehouses.FindAsync(id); return w==null?NotFound("Warehouse not found."):Ok(w);} [HttpPut("{id}/deactivate")] public async Task<IActionResult> Deactivate(int id){var w=await _context.Warehouses.FindAsync(id); if(w==null)return NotFound("Warehouse not found."); await _spService.UpdateWarehouseAsync(id,new WarehouseUpdateDto{Name=w.Name,Location=w.Location,IsActive=false}); return Ok("Warehouse deactivated successfully.");} [HttpDelete("{id}")] public async Task<IActionResult> Delete(int id){var w=await _context.Warehouses.FindAsync(id); if(w==null)return NotFound("Warehouse not found."); _context.Warehouses.Remove(w); await _context.SaveChangesAsync(); return Ok("Warehouse deleted successfully.");}}
